@register.simple_tag
def icon(name, css_class='sidebar-icon'):
    svg = ICONS.get(name, '')
    if not svg:
        return mark_safe(f'<span style="width:20px;height:20px;display:inline-block;"></span>')
    # Inject class into SVG
    svg = svg.replace('<svg ', f'<svg class="{css_class}" ', 1)
    return mark_safe(svg)


