@register.simple_tag
def emotion_icon(emotion_key, size=36):
    svg = EMOTION_SVGS.get(emotion_key, EMOTION_SVGS['calm'])
    if size != 36:
        svg = svg.replace('width="36" height="36"', f'width="{size}" height="{size}"')
    return mark_safe(svg)
